mapper.select:
select ti.id, ti.sn, ti.upc from ter_info ti LEFT JOIN ter_gateway tg on (ti.gateway = tg.sn) left join building_info bi on (tg.building_id = bi.id) inner join sys_dept d on (bi.dept_id = d.dept_id)
ti.del_flag = '0' and (ti.sn = #{sn} or ti.upc = #{sn})
${params.dataScope}

mapper.update:
update ter_info
sn = #{sn}, upc = #{upc}, ter_status = #{terStatus}, gateway = #{gateway}, created_by = #{createdBy}, created_time = #{createdTime}, updated_by = #{updatedBy}, updated_time = #{updatedTime}, del_flag = #{delFlag}, dept_id = #{deptId},
where id = #{id}
